// El mismo resumen corto del workflow 07, pero este no se da por publicado
// solo: termina pidiendo una respuesta explícita. Sin esa palabra en el chat,
// el segundo tramo de este workflow nunca lo va a dar por aprobado.
const proyectos = $input.all().map((item) => item.json);

const conteos = { ROJO: 0, AMBAR: 0, VERDE: 0 };
for (const proyecto of proyectos) {
  conteos[proyecto.semaforo] = (conteos[proyecto.semaforo] || 0) + 1;
}

const decisiones = proyectos.filter((proyecto) => proyecto.necesita_decision);

const fecha = new Date().toLocaleDateString('es-CO', { day: 'numeric', month: 'long' });
const lineas = [
  `📋 Informe listo para publicar — ${fecha}`,
  `🔴 ${conteos.ROJO} bloqueados · 🟡 ${conteos.AMBAR} en riesgo · 🟢 ${conteos.VERDE} en curso`,
];

if (decisiones.length > 0) {
  lineas.push('', 'Requieren una decisión:');
  for (const proyecto of decisiones) {
    lineas.push(`• ${proyecto.proyecto} — ${proyecto.responsable}`);
  }
}

lineas.push('', 'Responde APRUEBO en este chat para publicarlo.');

return [{ json: { mensaje: lineas.join('\n') } }];

// getUpdates devuelve todos los mensajes recientes que el bot todavía no
// "consumió", más viejo primero. Solo nos importa el último, y solo si trae
// la palabra que pedimos en el mensaje anterior.
const respuesta = $input.first().json;
const mensajes = respuesta.result || [];
const ultimo = mensajes[mensajes.length - 1];
const texto = ultimo?.message?.text || '';

return [{
  json: {
    aprobado: texto.toUpperCase().includes('APRUEBO'),
    ultimoMensaje: texto,
    quien: ultimo?.message?.from?.first_name || 'desconocido',
  },
}];
